const r = $json;
const res = r.results || r;
let arr = res.groups || res.data || (Array.isArray(res) ? res : []);
if (!Array.isArray(arr)) arr = [];
const sendTo = ($('Quick Setup Form').first().json['Summary recipient number'] || '').trim();
if (!sendTo) throw new Error('Masukkan nomor penerima ringkasan (contoh: 628xxxxxxxxxx).');
const rows = arr
  .map(g => ({ chat_jid: g.JID || g.jid || g.id || '', project_name: g.name || g.subject || 'Group', send_to: sendTo }))
  .filter(x => String(x.chat_jid).endsWith('@g.us'));
if (!rows.length) throw new Error('Tidak ada grup dari go-wa. Pastikan go-wa aktif & kredensial benar.');
return rows.map(x => ({ json: x }));

const n = $('Map Groups to Rows').all().length;
const to = ($('Quick Setup Form').first().json['Summary recipient number'] || '').trim();
const resultMessage =
  '✅ Setup selesai! ' + n + ' grup didaftarkan.\n' +
  'Ringkasan harian dikirim ke ' + to + ' setiap hari pukul 23:00 WIB.\n\n' +
  'Pastikan workflow "WAG Chat — Ingest" dan "WAG Chat — Daily Summary" sudah Active.';
return [{ json: { resultMessage } }];
